import React from "react";
import {
  LayoutDashboard,
  CalendarDays,
  BarChart2,
  FileText,
  Settings,
} from "lucide-react";
import "./Sidebar.css";

const NAV_ITEMS = [
  { icon: LayoutDashboard, label: "Dashboard" },
  { icon: CalendarDays, label: "Planning", active: true },
  { icon: BarChart2, label: "Analytics" },
  { icon: FileText, label: "Reports" },
];

interface SidebarProps {
  isOpen?: boolean;          // mobile drawer open state
  onClose?: () => void;      // called when overlay is tapped
}

export const Sidebar: React.FC<SidebarProps> = ({ isOpen = false, onClose }) => {
  return (
    <>
      {/* Overlay — only rendered / visible on mobile */}
      <div
        className={`sidebar__overlay ${isOpen ? "open" : ""}`}
        onClick={onClose}
        aria-hidden="true"
      />

      <aside className={`sidebar ${isOpen ? "open" : ""}`}>
        {/* Logo */}
        <div className="sidebar__logo">
          <div className="sidebar__logo-mark">C</div>
          {/* Logo text shown inside mobile drawer */}
          <span className="sidebar__logo-text">Companyname</span>
        </div>

        {/* Main Nav */}
        <nav className="sidebar__nav">
          {NAV_ITEMS.map((item) => {
            const Icon = item.icon;
            return (
              <button
                key={item.label}
                className={`sidebar__nav-item ${item.active ? "active" : ""}`}
                title={item.label}
                aria-label={item.label}
              >
                <Icon size={18} />
                {/* Label shown inside mobile drawer */}
                <span className="nav-label">{item.label}</span>
              </button>
            );
          })}
        </nav>

        {/* Bottom Section */}
        <div className="sidebar__bottom">
          <button className="sidebar__nav-item" title="Settings" aria-label="Settings">
            <Settings size={18} />
            <span className="nav-label">Settings</span>
          </button>

          <button className="sidebar__profile" title="Profile" aria-label="Profile">
            <img src="https://i.pravatar.cc/40" alt="user" />
            {/* Profile info shown inside mobile drawer */}
            <span className="sidebar__profile-info">
              <span className="sidebar__profile-name">John Doe</span>
              <span className="sidebar__profile-role">Admin</span>
            </span>
          </button>
        </div>
      </aside>
    </>
  );
};
